const resolveWithTimeout = (promise, timeoutMs, timeoutValue) => {
  let timeoutId;
  const timeout = new Promise(resolve => {
    timeoutId = setTimeout(() => resolve(timeoutValue), timeoutMs);
  });
  return Promise.race([
    Promise.resolve(promise).finally(() => clearTimeout(timeoutId)),
    timeout,
  ]);
};

const rejectWithTimeout = (promise, timeoutMs, message) => {
  let timeoutId;
  const timeout = new Promise((_, reject) => {
    timeoutId = setTimeout(() => reject(new Error(message)), timeoutMs);
  });
  return Promise.race([
    Promise.resolve(promise).finally(() => clearTimeout(timeoutId)),
    timeout,
  ]);
};

const calcBentoPosition = (index, viewW, viewH, itemW = 420, itemH = 320) => {
  const gap = 20;
  const padX = 20;
  const padY = 20;
  // Reserve bottom space for taskbar (h-10 = 40px) + breathing room
  const reserveBottom = 60;
  const usableW = Math.max(itemW + padX * 2, viewW);
  const usableH = Math.max(itemH + padY * 2, viewH - reserveBottom);

  const cols = Math.max(1, Math.floor((usableW - padX * 2 + gap) / (itemW + gap)));
  const col = index % cols;
  const row = Math.floor(index / cols);

  let x = padX + col * (itemW + gap);
  let y = padY + row * (itemH + gap);

  // Clamp so the full artifact rectangle stays inside the usable viewport
  const maxX = Math.max(padX, usableW - itemW - padX);
  const maxY = Math.max(padY, usableH - itemH - padY);
  x = Math.max(padX, Math.min(x, maxX));
  y = Math.max(padY, Math.min(y, maxY));

  return { x, y };
};

const escapeHtml = (value = '') => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const clampNumber = (value, min, max) => Math.max(min, Math.min(max, value));

const getCoverImagePoint = (event, imageEl) => {
  if (!event || !imageEl) return null;
  const rect = imageEl.getBoundingClientRect();
  const naturalWidth = imageEl.naturalWidth || rect.width || 1;
  const naturalHeight = imageEl.naturalHeight || rect.height || 1;
  if (!rect.width || !rect.height || !naturalWidth || !naturalHeight) return null;

  const scale = Math.max(rect.width / naturalWidth, rect.height / naturalHeight);
  const drawnWidth = naturalWidth * scale;
  const drawnHeight = naturalHeight * scale;
  const offsetX = (rect.width - drawnWidth) / 2;
  const offsetY = (rect.height - drawnHeight) / 2;
  const localX = event.clientX - rect.left;
  const localY = event.clientY - rect.top;

  return {
    x: clampNumber((localX - offsetX) / scale, 0, naturalWidth),
    y: clampNumber((localY - offsetY) / scale, 0, naturalHeight),
    naturalWidth,
    naturalHeight,
  };
};

const loadImageForCanvas = (src) => new Promise((resolve, reject) => {
  const img = new window.Image();
  if (typeof src === 'string' && !src.startsWith('data:')) img.crossOrigin = 'anonymous';
  img.onload = () => resolve(img);
  img.onerror = () => reject(new Error('Could not load image for crop'));
  img.src = src;
});

const createInteractiveZoomCrop = async (imageUrl, point) => {
  const image = await loadImageForCanvas(imageUrl);
  const naturalWidth = image.naturalWidth || image.width || point.naturalWidth || 1024;
  const naturalHeight = image.naturalHeight || image.height || point.naturalHeight || 1024;
  const maxSide = Math.min(naturalWidth, naturalHeight);
  const side = Math.round(clampNumber(maxSide * 0.34, Math.min(224, maxSide), Math.min(768, maxSide)));
  const x = Math.round(clampNumber(point.x - side / 2, 0, Math.max(0, naturalWidth - side)));
  const y = Math.round(clampNumber(point.y - side / 2, 0, Math.max(0, naturalHeight - side)));
  const canvasSize = 768;
  const canvas = document.createElement('canvas');
  canvas.width = canvasSize;
  canvas.height = canvasSize;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Could not create crop canvas');
  ctx.drawImage(image, x, y, side, side, 0, 0, canvasSize, canvasSize);
  return {
    dataUrl: canvas.toDataURL('image/png'),
    bbox: { x, y, width: side, height: side },
    imageSize: { width: naturalWidth, height: naturalHeight },
  };
};

const buildInteractiveZoomPrompt = ({ title, point, crop }) => `You are powering an infinite-image zoom interaction.

Image 1 is the full source image. Image 2 is a square crop centered on the user's click. Interpret the clicked spot in the context of the full source image, then design the next generated image as if this clicked element were a clickable portal and the viewer zoomed into it.

Source title: ${title || 'Untitled image'}
Click coordinates: x=${Math.round(point.x)}, y=${Math.round(point.y)} within ${Math.round(crop.imageSize.width)}x${Math.round(crop.imageSize.height)}.
Crop rectangle: x=${crop.bbox.x}, y=${crop.bbox.y}, size=${crop.bbox.width}x${crop.bbox.height}.

Return STRICT JSON only:
{
  "label": "2-5 word name of what was clicked",
  "type": "object | person | place | ui | text | texture | symbol | scene",
  "description": "one sentence describing what the user clicked",
  "imagePrompt": "a detailed text-to-image prompt for a square image that feels like zooming into that clicked thing while preserving the parent image's style, lighting, material, palette, and world logic"
}

The imagePrompt must describe a new standalone square image. Do not request text, labels, captions, UI chrome, watermarks, or split-screen comparison.`;

const normalizeInteractiveZoomAnalysis = (raw, fallbackLabel) => {
  const parsed = safeExtractJSON(raw) || {};
  const label = typeof parsed.label === 'string' && parsed.label.trim()
    ? parsed.label.trim().slice(0, 48)
    : fallbackLabel;
  const type = typeof parsed.type === 'string' && parsed.type.trim()
    ? parsed.type.trim().slice(0, 32)
    : 'scene';
  const description = typeof parsed.description === 'string' && parsed.description.trim()
    ? parsed.description.trim().slice(0, 280)
    : `Zoomed exploration of ${label}`;
  const imagePrompt = typeof parsed.imagePrompt === 'string' && parsed.imagePrompt.trim()
    ? parsed.imagePrompt.trim()
    : `Square image, close-up zoom into ${label}, preserving the parent image style, lighting, palette, materials, and atmosphere. High detail, immersive, no text, no watermark.`;
  return { label, type, description, imagePrompt };
};

