const DEFAULT_APP_SETTINGS = {
  defaultSonarModel: 'sonar',
  defaultAiModel: DEFAULT_AI_MODEL,
  // 'fast' = skip the analysis phase, emit find/replace blocks immediately.
  // 'extended' = the original two-phase Architect prompt (Phase 1 analysis, Phase 2 patches).
  crisprMode: 'extended',
};
const DEFAULT_DESKTOP_BACKGROUND = {
  type: 'gradient',
  value: 'linear-gradient(135deg, #101827 0%, #12313a 32%, #2a223c 66%, #1d2734 100%)',
};

const normalizeAppSettings = (settings = {}) => {
  const merged = {
    ...DEFAULT_APP_SETTINGS,
    ...(settings && typeof settings === 'object' ? settings : {}),
  };
  if (merged.crisprMode !== 'fast' && merged.crisprMode !== 'extended') {
    merged.crisprMode = DEFAULT_APP_SETTINGS.crisprMode;
  }
  return merged;
};

const formatDesignSystemValue = (value) => {
  if (Array.isArray(value)) return value.filter(Boolean).join(', ');
  if (value && typeof value === 'object') {
    return Object.entries(value)
      .map(([key, val]) => `${key}: ${formatDesignSystemValue(val)}`)
      .join('; ');
  }
  return String(value ?? '');
};

