  function exportDesignMd(ds) {
    const lines = ['---', `name: ${ds.name}`];
    if (ds.description) lines.push(`description: "${ds.description.replace(/"/g, "'")}"`);
    if (ds.palette) {
      lines.push('colors:');
      const p = ds.palette;
      const colorMap = { primary: p.primary, surface: p.secondary, accent: p.accent, background: p.background, foreground: p.foreground, neutral: p.muted };
      for (const [k, v] of Object.entries(colorMap)) { if (v && typeof v === 'string') lines.push(`  ${k}: "${v}"`); }
      if (Array.isArray(p.extras)) { for (const e of p.extras) { if (e?.hex) lines.push(`  ${e.name}: "${e.hex}"`); } }
    }
    if (ds.typography) {
      lines.push('typography:');
      const t = ds.typography;
      if (t.headingFont) { lines.push('  h1:'); lines.push(`    fontFamily: ${t.headingFont}`); lines.push(`    fontWeight: 700`); }
      if (t.bodyFont) { lines.push('  body-md:'); lines.push(`    fontFamily: ${t.bodyFont}`); lines.push(`    fontSize: 0.875rem`); }
      if (t.monoFont) { lines.push('  code:'); lines.push(`    fontFamily: ${t.monoFont}`); }
    }
    if (ds.spacing?.scale) {
      lines.push('spacing:');
      const labels = ['xs','sm','md','lg','xl','2xl','3xl'];
      (ds.spacing.scale || []).forEach((v, i) => { if (labels[i]) lines.push(`  ${labels[i]}: ${v}`); });
    }
    lines.push('---', '', '## Overview', '', ds.description || ds.notes || '');
    if (ds.tone) { lines.push('', `Voice: ${ds.tone.voice || ''}. ${ds.tone.personality || ''}`); }
    if (ds.layout) {
      lines.push('', '## Layout', '');
      Object.entries(ds.layout).forEach(([k, v]) => lines.push(`- ${k}: ${formatDesignSystemValue(v)}`));
    }
    if (ds.ux) {
      lines.push('', '## UX', '');
      Object.entries(ds.ux).forEach(([k, v]) => lines.push(`- ${k}: ${formatDesignSystemValue(v)}`));
    }
    if (ds.motion) lines.push('', '## Motion', '', formatDesignSystemValue(ds.motion));
    if (ds.imagery) lines.push('', '## Imagery', '', formatDesignSystemValue(ds.imagery));
    if (Array.isArray(ds.avoid) && ds.avoid.length) {
      lines.push('', "## Do's and Don'ts", '', "**Don't:**");
      ds.avoid.forEach(a => lines.push(`- ${a}`));
    }
    if (ds.notes) { lines.push('', '## Notes', '', ds.notes); }
    return lines.join('\n');
  }

