  // ─── Multimodal Attachments ────────────────────────────────────────────
  // The image-attachment flow is separate from useFileImport because vision
  // models need base64 data URLs (not blob: URLs which the server can't
  // resolve). Cap to 4 images / 4MB each so we never blow Anthropic's
  // 5MB-per-image hard limit.
  const MAX_ATTACHED_IMAGES = 4;
  const MAX_ATTACHED_IMAGE_BYTES = 4_000_000;
  const fileToDataUrl = useCallback((file) => new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = () => reject(reader.error || new Error('read failed'));
    reader.readAsDataURL(file);
  }), []);
  const addAttachedImage = useCallback(async (file) => {
    if (!file || !file.type || !file.type.startsWith('image/')) return;
    if (file.size > MAX_ATTACHED_IMAGE_BYTES) {
      toast({ title: 'Image too large', description: `${(file.size / 1_000_000).toFixed(1)}MB — max ${(MAX_ATTACHED_IMAGE_BYTES / 1_000_000).toFixed(0)}MB`, variant: 'destructive' });
      return;
    }
    let didOverflow = false;
    setDesktopAttachedImages(prev => {
      if (prev.length >= MAX_ATTACHED_IMAGES) {
        didOverflow = true;
        return prev;
      }
      return prev;
    });
    if (didOverflow) {
      toast({ title: 'Attachment limit reached', description: `Max ${MAX_ATTACHED_IMAGES} images per prompt` });
      return;
    }
    try {
      const dataUrl = await fileToDataUrl(file);
      if (typeof dataUrl !== 'string' || !dataUrl.startsWith('data:image/')) {
        throw new Error('Invalid image data');
      }
      setDesktopAttachedImages(prev => [...prev, {
        id: `img-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
        dataUrl,
        name: file.name || 'image',
        mime: file.type,
        size: file.size,
      }]);
    } catch (err) {
      toast({ title: 'Could not attach image', description: err?.message || 'Unknown error', variant: 'destructive' });
    }
  }, [fileToDataUrl, toast]);
